update tb_move_req
set    move_reg_date = #{moveReqDate}
      ,reg_seq      = #{reqSeq}
      ,move_status  = #{moveStatus}
      ,upd_id       = #{userId}
      ,upd_dt       = getdate()
where  move_req_id  = #{moveReqId}

UPDATE tb_move_item
SET item_type_cd = #{itemTypeCd}
  , item_cd      = #{itemCd}
  , test_no      = #{testNo}
  , qty          = #{qty}
  , etc          = #{etc}
  , upd_id       = #{userId}
  , upd_dt       = GETDATE()
WHERE move_item_id = #{moveItemId}
